def find_first_occurrence(nums, target) -> int:
    def binary_search(low, high):
        if low > high:
            return -1
        mid = (low + high) // 2
        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            return binary_search(mid + 1, high)
        else:
            return binary_search(low, mid - 1)
    return binary_search(0, len(nums) - 1)

